.cw-input {
  display: flex;
  position: relative;
  width: 60px;
  height: 60px;
  --cw-a: #0004, #fff4;
  --cw-b: var(--cw-a), var(--cw-a), var(--cw-a);
  --cw-c: var(--cw-b), var(--cw-b), var(--cw-b);
  background: conic-gradient(
      from -2deg,
      #efefff88,
      #00000088,
      #efefff88,
      #00000088,
      #efefff88
    ),
    radial-gradient(var(--cw-c), var(--cw-c)),
    radial-gradient(circle at 12% 12%, #efefff, #9999a4);
  background-size: calc(100% + 8px) calc(100% + 8px);
  background-position: -4px -4px;
  border: 4px solid #0005;
  border-radius: 50%;
}

.cw-input input {
  display: none;
  pointer-events: none;
}

.cw-dial {
  position: absolute;
  width: 26px;
  height: 4px;
  border-radius: 99px;
  background-color: #000b;
  top: calc(50% - 2px);
  left: calc(50% - 2px);
  transform-origin: 2px 50%;
  pointer-events: none;
  transition: 0.15s;
  animation: cw-owo 0.15s;
}

@keyframes cw-owo {
  0% {
    transform: rotate(-60deg);
  }
  to {
    transform: rotate(0deg);
  }
}

.cw-input label {
  position: absolute;
  width: 48px;
  height: 48px;
  cursor: pointer;
}

#cw-v1:checked ~ #cw-l2 {
  z-index: 2;
}
#cw-v1:checked ~ .cw-dial {
  transform: rotate(0deg);
}

#cw-v2:checked ~ #cw-l3 {
  z-index: 2;
}
#cw-v2:checked ~ .cw-dial {
  transform: rotate(60deg);
  animation: none;
}

#cw-v3:checked ~ #cw-l4 {
  z-index: 2;
}
#cw-v3:checked ~ .cw-dial {
  transform: rotate(120deg);
  animation: none;
}

#cw-v4:checked ~ #cw-l5 {
  z-index: 2;
}
#cw-v4:checked ~ .cw-dial {
  transform: rotate(180deg);
  animation: none;
}

#cw-v5:checked ~ #cw-l6 {
  z-index: 2;
}
#cw-v5:checked ~ .cw-dial {
  transform: rotate(240deg);
  animation: none;
}

#cw-v6:checked ~ #cw-l1 {
  z-index: 2;
}
#cw-v6:checked ~ .cw-dial {
  transform: rotate(300deg);
  animation: none;
}

.cw-notch {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 8px;
  height: 1px;
  background-color: #fffc;
  transform: translate(-50%) rotate(calc((var(--cw-n) - 1) * 60deg))
    translateX(38px);
  counter-reset: section;
}

.cw-notch::before {
  content: counter(section);
  position: absolute;
  counter-set: section var(--cw-n);
  color: #fffc;
  transform: translate(12px, -50%) rotate(calc((var(--cw-n) - 1) * -60deg));
  font-size: 12px;
}

.rb-input {
  display: flex;
  align-items: center;
  gap: 6px;
  background-color: black;
  padding: 6px;
  border-radius: 8px;
  overflow: hidden;
  height: 94px;
}

.rb-input input {
  display: none;
}

.rb-input .rb-label {
  width: 70px;
  height: 80px;
  background-color: #e8dcc4;
  border-radius: 4px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  padding: 8px 6px;
  border-top: 1px solid #a89878;
  transition: all 0.1s linear;
  position: relative;
  z-index: 2;
}

.rb-label .rb-back-side {
  position: absolute;
  top: -10px;
  left: 0px;
  background-color: #e8dcc4;
  border-radius: 4px 4px 2px 2px;
  width: 100%;
  height: 14px;
  box-shadow:
    inset 0 5px 3px 1px rgba(0, 0, 0, 0.5),
    inset 0px -5px 2px 0px rgba(56, 163, 224, 0.1);
  transform: perspective(300px) rotateX(50deg);
  z-index: 1;
  opacity: 0;
  transition: all 0.1s linear;
}

.rb-label:has(input[type="radio"]:checked) .rb-back-side {
  opacity: 1;
}

.rb-label:has(input[type="radio"]:checked) {
  transform: perspective(200px) rotateX(-18deg);
  transform-origin: 50% 40%;
  box-shadow: inset 0px -20px 15px 0px rgba(0, 0, 0, 0.5);
  border-top: 1px solid #2589c362;
  margin-top: 6px;
  border-radius: 0 0 4px 4px;
}

.rb-label .rb-text {
  color: black;
  font-size: 15px;
  line-height: 12px;
  padding: 0px;
  font-weight: 800;
  text-transform: uppercase;
  transition: all 0.1s linear;
  text-shadow: -1px -1px 1px rgb(224, 224, 224, 0.1);
}

.rb-label input[type="radio"]:checked + .rb-text {
  color: #258ac3;
  text-shadow:
    0px 0px 8px rgb(37, 138, 195),
    1px 1px 2px rgb(0, 0, 0, 1);
}

.rb-label .rb-bottom-line {
  width: 100%;
  height: 4px;
  border-radius: 999px;
  background-color: #d4c4a0;
  box-shadow: 0 0 3px 0px rgb(19, 19, 19);
  border-top: 1px solid #a89878;
  transition: all 0.1s linear;
}

.rb-label:has(input[type="radio"]:checked) .rb-bottom-line {
  background-color: #c4b490;
  border-top: 1px solid #258ac340;
}

.ri-input {
  display: flex;
  align-items: center;
  gap: 2px;
  background-color: black;
  padding: 4px;
  border-radius: 10px;
  z-index: -1;
}

.ri-input input {
  display: none;
}

.ri-input .ri-label {
  width: 90px;
  height: 60px;
  background: linear-gradient(to bottom, #333333, rgb(36, 35, 35));
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 8px;
  transition: all 0.1s linear;
  border-top: 1px solid #4e4d4d;
  position: relative;
  cursor: pointer;
  box-shadow: 0px 17px 5px 1px rgba(0, 0, 0, 0.2);
}

.ri-label:has(input[type="radio"]:checked) {
  box-shadow: 0px 17px 5px 1px rgba(0, 0, 0, 0);
  background: linear-gradient(to bottom, #1d1d1d, #1d1d1d);
  border-top: none;
}

.ri-label:first-child {
  border-top-left-radius: 6px;
  border-bottom-left-radius: 6px;
}

.ri-label:last-child {
  border-top-right-radius: 6px;
  border-bottom-right-radius: 6px;
}

.ri-label::before {
  content: "";
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 103%;
  height: 100%;
  border-radius: 10px;
  background: linear-gradient(
    to bottom,
    transparent 10%,
    transparent,
    transparent 90%
  );
  transition: all 0.1s linear;
  z-index: -1;
}

.ri-label:has(input[type="radio"]:checked)::before {
  background: linear-gradient(
    to bottom,
    transparent 10%,
    #cae2fd63,
    transparent 90%
  );
}

.ri-label .ri-text {
  color: black;
  font-size: 15px;
  line-height: 12px;
  padding: 0px;
  font-weight: 800;
  text-transform: uppercase;
  transition: all 0.1s linear;
  text-shadow:
    -1px -1px 1px rgb(224, 224, 224, 0.1),
