.pr-wrapper {
  --printer-color: #dcdac4;
  --printer-color-2: #c0beaa;
  --receipt-color: #f5f5f5;

  font-size: 14px;
  position: relative;
  user-select: none;
}

.pr-machine {
  width: 320px;
  height: 80px;
  border-radius: 0 0 8px 8px;

  background-color: var(--printer-color);
  background-image: url(data:image/png;base64,);
  border: 2px solid var(--printer-color-2);
  box-shadow:
    0 16px 32px 0px #0002,
    0 -30px 16px 0px #0001;
}

.pr-machine::before {
  content: "";
  position: absolute;
  top: -30px;
  left: 0;
  width: 100%;
  height: 70px;
  border-radius: 12px 12px 0 0;
  border-bottom: 2px solid #0003;
  box-shadow:
    0 12px 16px -12px #fff5 inset,
    0 -6px 16px -6px #0003 inset,
    0 6px 8px -6px #0004;
  box-sizing: border-box;
  background-color: inherit;
  background-image: inherit;
  filter: brightness(1.12);
  z-index: 2;
}

.pr-machine::after {
  content: "";
  position: absolute;
  top: 20px;
  left: 30px;
  width: 260px;
  height: 40px;
  border-radius: 0 0 4px 4px;
  border-bottom: 1px solid #0003;
  background-color: inherit;
  background-image: linear-gradient(
    to top,
    var(--printer-color),
    60%,
    var(--printer-color-2)
  );
  box-shadow: 0 4px 4px -2px #0004;

  z-index: 1;
}

.pr-screen {
  z-index: 2;

  display: flex;
  padding: 6px 8px;
  position: absolute;
  top: -10px;
  left: 30px;
  width: 160px;
  height: 32px;

  background-color: #000;
  background-image: linear-gradient(transparent 0, #fff2 90%, transparent 100%);
  background-size: 100% 8px;
  background-repeat: no-repeat;
  border: 3px solid var(--printer-color-2);
  border-radius: 6px;
  box-sizing: border-box;
  box-shadow:
    -1px -1px 2px 0 #fff9 inset,
    1px 1px 5px 1px #000 inset,
    0 0 1px 2px #0002;

  font-family: "Courier New", Courier, monospace;
  font-size: 0.8em;
  color: #5aff5a;
  filter: drop-shadow(1px 1px 1px #0002);
}

.pr-btn {
  z-index: 2;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2em;
  position: absolute;
  top: -30px;
  right: 0;
  margin: 16px;
  border: 1px solid #0001;
  border-radius: 6px;
  width: 48px;
  height: 36px;
  background-color: var(--printer-color);
  box-shadow:
    1px 1px 2px 0 #fff8 inset,
    -1px -1px 2px 0 #0002 inset,
    0 2px 6px 0px #0002;
  transition:
    box-shadow 0.1s ease-in-out,
    transform 0.1s ease-in-out;
}

.pr-btn:hover {
  box-shadow:
    2px 2px 2px 0 #fff9 inset,
    -2px -2px 2px 0 #0002 inset,
    0 2px 10px 0px #0002;
  transform: scale(1.05);
}
.pr-btn:active {
  box-shadow:
    2px 2px 2px 0 #0002 inset,
    -2px -2px 2px 0 #fff9 inset,
    0 0px 4px 0px #fff9;
  transform: scale(0.95);
}

.pr-receipt-wrap {
  position: absolute;
  top: 0;
  left: 44px;
  filter: drop-shadow(0 0 12px #0001);
  transform: translateY(-100%);
  clip-path: inset(100% -100px -100px -100px);
  transition: clip-path 0.5s;
}

.pr-receipt {
  z-index: 2;
  position: relative;

  display: flex;
  flex-direction: column;
  gap: 1em;

  padding: 16px;
  width: 200px;
  min-height: 160px;

  font-size: 0.75em;
  font-family: "Azeret Mono", "Roboto Mono", monospace;
  font-weight: 400;
  color: #444;

  background-color: var(--receipt-color);
  box-shadow:
    0 12px 12px 0 #0001,
    0 24px 24px 0 #0001,
    0 36px 36px 0 #0001;
}

.pr-receipt::before,
.pr-receipt::after {
  --angle: 45deg;

  content: "";
  display: block;
  position: absolute;
  left: 0px;
  width: 100%;
  height: 8px;

  background: linear-gradient(
      calc(var(--angle) * -1),
      var(--receipt-color) 4px,
      transparent 0
    ),
    linear-gradient(var(--angle), var(--receipt-color) 4px, transparent 0);
  background-position: 4px 0;
  background-repeat: repeat-x;
  background-size: 8px 8px;
}
.pr-receipt::before {
  top: -8px;
  background-position: 4px 0;
}
.pr-receipt::after {
  bottom: -8px;
  background-position: 0 100%;
  --angle: 225deg;
}

.pr-head,
.pr-subhead,
.pr-message {
  display: flex;
  justify-content: space-between;
  padding: 0.2em 0;
}

.pr-head {
  font-size: 1.1em;
  font-weight: 600;
}
.pr-subhead {
  border-bottom: 1px dashed #ccc;
}
.pr-message {
  justify-content: center;
  text-align: center;
  padding: 0 1em;
}

.pr-logo {
  width: 48px;
  font-size: 3em;
  transform: rotate(10deg);
  filter: grayscale(1);
}

.pr-subtotal td,
.pr-total td {
  border-top: 1px dashed #ccc;
}

.pr-total td {
  font-weight: 600;
}

.pr-table {
  font: inherit;
  color: inherit;
  text-align: left;
  line-height: 1.5em;

  th:last-child,
  td:last-child {
    text-align: right;
  }
  td:last-child::after {
    content: " $";
  }
}

.pr-letters {
  position: inherit;
  display: flex;
}

.pr-letter {
  display: inline-block;
  opacity: 0;
}

.pr-wrapper:has(.pr-btn:focus) {
  .pr-receipt-wrap {
    animation:
      pr-print 1.2s 1 forwards ease-in,
      pr-display 0.4s 1 forwards cubic-bezier(0, 0.63, 0.96, 1.1);
    animation-delay: 0s, 1.35s;
  }

  .pr-msg {
    opacity: 0;
  }

  .pr-letter:nth-child(1) { animation-delay: 0.05s; }
  .pr-letter:nth-child(2) { animation-delay: 0.1s; }
  .pr-letter:nth-child(3) { animation-delay: 0.15s; }
  .pr-letter:nth-child(4) { animation-delay: 0.2s; }
  .pr-letter:nth-child(5) { animation-delay: 0.25s; }
  .pr-letter:nth-child(6) { animation-delay: 0.3s; }
  .pr-letter:nth-child(7) { animation-delay: 0.35s; }
  .pr-letter:nth-child(8) { animation-delay: 0.4s; }
  .pr-letter:nth-child(9) { animation-delay: 0.45s; }
  .pr-letter:nth-child(10) { animation-delay: 0.5s; }
  .pr-letter:nth-child(11) { animation-delay: 0.55s; }
  .pr-letter:nth-child(12) { animation-delay: 0.6s; }

  .pr-letter {
    animation: pr-show 0.6s 1 forwards linear;
  }
}

@keyframes pr-print {
  100% {
    transform: translateY(10%);
    clip-path: inset(-20% -100px -100px -100px);
  }
}

@keyframes pr-display {
  30% {
    transform: translateY(22%) rotate3d(1, 0, 1, -5deg);
  }
  70% {
    z-index: 5;
  }
  100% {
    z-index: 5;
    transform: translateY(-40%) scale(1.2);
  }
}

@keyframes pr-show {
  10%,
  100% {
    opacity: 1;
  }
}

