.fc-nums {
  box-shadow:
    8px 8px 15px rgba(42, 42, 42, 0.2),
    -8px -8px 15px rgba(255, 255, 255, 0.5);
  display: inline-block;
  height: 200px;
  perspective: 1000px;
  position: relative;
  width: 140px;
  border-radius: 20px 20px 20px 20px;
}

.fc-nums:before {
  border-bottom: 1px solid #d2d2d2;
  content: "";
  height: 1px;
  left: 0;
  position: absolute;
  transform: translate3d(0, -1px, 0);
  top: 50%;
  width: 100%;
  z-index: 1000;
}

.fc-nums:after {
  backface-visibility: hidden;
  background: #e0e0e0;
  border-radius: 0 0 20px 20px;
  bottom: 0;
  color: #333;
  content: "0";
  display: block;
  font-size: 145px;
  height: calc(50% - 1px);
  left: 0;
  line-height: 0;
  overflow: hidden;
  position: absolute;
  text-align: center;
  text-shadow:
    0 1px 1px rgba(0, 0, 0, 0.05),
    0 2px 4px rgba(0, 0, 0, 0.08);
  width: 100%;
  z-index: 0;
}

.fc-num {
  animation-fill-mode: forwards;
  animation-iteration-count: infinite;
  animation-timing-function: ease-in;
  border-radius: 20px;
  font-size: 145px;
  height: 100%;
  left: 0;
  position: absolute;
  transform: rotateX(0);
  transition: 0.6s;
  transform-style: preserve-3d;
  top: 0;
  width: 100%;
}

.fc-num:before,
.fc-num:after {
  backface-visibility: hidden;
  color: #333;
  display: block;
  height: 50%;
  left: 0;
  overflow: hidden;
  position: absolute;
  text-align: center;
  text-shadow:
    0 1px 1px rgba(0, 0, 0, 0.05),
    0 2px 4px rgba(0, 0, 0, 0.08);
  width: 100%;
}

.fc-num:before {
  background: #e0e0e0;
  border-radius: 20px 20px 0 0;
  content: attr(data-num);
  line-height: 1.38;
  top: 0;
  z-index: 1;
}

.fc-num:after {
  background: #e0e0e0;
  border-bottom: 1px solid #d2d2d2;
  border-radius: 0 0 20px 20px;
  content: attr(data-num-next);
  height: calc(50% - 1px);
  line-height: 0;
  top: 0;
  transform: rotateX(180deg);
}
