  font-size: 11px;
  font-weight: bold;
  text-transform: uppercase;
  color: rgb(192, 33, 33);
  z-index: 2000;
}

.rd-container {
  width: 280px;
  height: 380px;
  background-color: #151716;
  border-radius: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  filter: hue-rotate(10deg);
  color: #2fbb39;
  gap: 20px;
}

.rd-data {
  margin-top: 25px;
  border: 2px solid;
  padding: 15px;
  border-radius: 5px;
  background: #000000;
}

.rd-data::after {
  background: #000000;
  content: "WIND - 54,3";
  position: absolute;
  bottom: 5%;
  right: 5%;
  border: 2px solid;
  padding: 3px;
  border-radius: 5px;
  font-size: 0.7em;
}

.rd-data::before {
  content: "DEPT - 600";
  position: absolute;
  bottom: 5%;
  left: 5%;
  border: 2px solid;
  padding: 3px;
  border-radius: 5px;
  font-size: 0.7em;
  background: #000000;
}

.rd-card {
  width: 200px;
  height: 200px;
  background: #000000;
  border-radius: 50%;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 2px solid #18d322;
  overflow: hidden;
}

.rd-card::after {
  content: "";
  position: absolute;
  width: 2px;
  height: 200px;
  left: 50%;
  top: 50%;
  background-color: #18d322;
  animation: rd-rotate 3s linear infinite;
  z-index: 6;
  transform-origin: 0 0;
}

.rd-card::before {
  content: "";
  position: absolute;
  width: 0px;
  height: 200px;
  left: 50%;
  top: 50%;
  transform: rotate(-4deg);
  background-color: #18d322;
  animation: rd-rotate 3s linear infinite;
  box-shadow: 0 0 10px 10px #2fbb39, 0 0 70px 10px #2fbb39;
  z-index: 6;
  transform-origin: 0 0;
}

.rd-circle {
  width: 100px;
  height: 100px;
  border: 2px solid #18d322;
  border-radius: 50%;
}

.rd-circle::before {
  content: "";
  position: absolute;
  width: 50px;
  height: 50px;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  border: 2px solid #18d322;
  border-radius: 50%;
}

.rd-circle::after {
  content: "";
  position: absolute;
  width: 150px;
  height: 150px;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  border: 2px solid #18d322;
  border-radius: 50%;
}

.rd-dot {
  width: 4px;
  height: 4px;
  top: 30%;
  background-color: #18d322;
  border-radius: 50%;
  position: absolute;
  animation: rd-doted 1.5s ease infinite;
}

.rd-dot2 {
  width: 4px;
  height: 4px;
  top: 80%;
  right: 30%;
  background-color: #18d322;
  border-radius: 50%;
  position: absolute;
  animation: rd-doted 1.5s 1.2s ease infinite;
}

@keyframes rd-rotate {
  0% {
    transform: rotate(0deg);
  }

  100% {
    transform: rotate(360deg);
  }
}

@keyframes rd-doted {
  0% {
    transform: scale(0.95);
    box-shadow: 0 0 10px 5px rgba(24, 211, 33, 0.3),
      0 0 10px 10px rgba(24, 211, 33, 0.3);
  }

  60% {
    transform: scale(0.95);
    box-shadow: 0 0 10px 5px rgba(24, 211, 33, 0.3),
      0 0 10px 10px rgba(24, 211, 33, 0.3);
  }

  100% {
    transform: scale(1);
    box-shadow: 0 0 0 0 rgba(24, 211, 33, 0.7), 0 0 0 0 rgba(24, 211, 33, 0.5),
      0 0 0 0 rgba(24, 211, 33, 0.3);
    opacity: 0;
  }
}

.pb-wrapper {
  --pip-green: #1aff40;
  --pip-glow: rgba(26, 255, 64, 0.6);
  --bg-dark: #020a02;
  --chassis-dark: #1a1a1a;
  display: flex;
  justify-content: center;
  align-items: center;
  font-family: "Courier New", Courier, monospace;
  text-transform: uppercase;
  width: 100%;
  max-width: 460px;
  padding: 0.5rem;
  box-sizing: border-box;
  container-type: inline-size;
  container-name: pb-wrapper;
}

.pb-wrapper ::selection {
  background-color: var(--pip-green);
  color: var(--bg-dark);
  text-shadow: none;
}
.pb-wrapper ::-moz-selection {
  background-color: var(--pip-green);
  color: var(--bg-dark);
  text-shadow: none;
}

.pb-wrapper input[type="radio"] {
  display: none;
}

.pb-chassis {
  position: relative;
  width: 100%;
  background-image: radial-gradient(
      rgba(255, 255, 255, 0.04) 1px,
      transparent 1px
    ),
    linear-gradient(135deg, #2b2b2b, #111, #222);
  background-size:
    3px 3px,
    100% 100%;
  padding: 1.5rem;
  border-radius: 1.5rem;
  box-shadow:
    inset 0 0 20px #000,
    0 20px 40px rgba(0, 0, 0, 0.8),
    0 0 0 2px #333,
    0 5px 15px rgba(26, 255, 64, 0.1);
  border: 2px solid #444;
  box-sizing: border-box;
}

.pb-screw {
  position: absolute;
  width: 14px;
  height: 14px;
  background: linear-gradient(45deg, #555, #111);
  border-radius: 50%;
  border: 1px solid #000;
  box-shadow: inset 1px 1px 2px rgba(255, 255, 255, 0.2);
}

.pb-screw::after {
  content: "";
  position: absolute;
  top: 50%;
  left: 50%;
  width: 10px;
  height: 2px;
  background: #000;
  transform: translate(-50%, -50%) rotate(45deg);
}
.pb-tl {
  top: 15px;
  left: 15px;
}
.pb-tr {
  top: 15px;
  right: 15px;
  transform: rotate(90deg);
}
.pb-bl {
  bottom: 15px;
  left: 15px;
  transform: rotate(180deg);
}
.pb-br {
  bottom: 15px;
  right: 15px;
  transform: rotate(270deg);
}

.pb-crt {
  background-color: var(--bg-dark);
  border-radius: 1rem;
  position: relative;
  overflow: hidden;
  border: 6px solid #0a0a0a;
  box-shadow:
    inset 0 0 60px rgba(0, 0, 0, 1),
    0 0 10px rgba(0, 0, 0, 0.8);
  aspect-ratio: 5/4;
  cursor: crosshair;
}

.pb-glass {
  position: absolute;
  inset: 0;
  z-index: 10;
  pointer-events: none;
  background: radial-gradient(
    circle at 50% 50%,
    rgba(255, 255, 255, 0.03) 0%,
    rgba(0, 0, 0, 0.4) 80%
  );
  box-shadow: inset 0 0 50px rgba(0, 0, 0, 0.9);
}

.pb-glass::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 15%;
  background: linear-gradient(
    to bottom,
    transparent,
    rgba(26, 255, 64, 0.1),
    transparent
  );
  animation: pb-crt-scanline 7s linear infinite;
  pointer-events: none;
  z-index: 11;
}

.pb-scanlines {
  position: absolute;
  inset: 0;
  z-index: 9;
  pointer-events: none;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%);
  background-size: 100% 4px;
}

.pb-boot {
  height: 100%;
  padding: 0.8rem;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  color: var(--pip-green);
  text-shadow: 0 0 4px var(--pip-glow);
  animation: pb-turn-on 1.2s cubic-bezier(0.23, 1, 0.32, 1) forwards;
  opacity: 0;
}

.pb-bold {
  font-weight: 900;
}
.pb-line {
  height: 2px;
  background-color: var(--pip-green);
  box-shadow: 0 0 8px var(--pip-glow);
  opacity: 0.8;
}
.pb-flexible {
  flex-grow: 1;
  margin: 0 5px;
}

.pb-top-bar,
.pb-bottom-bar {
  display: flex;
  align-items: center;
  font-size: 0.6rem;
  font-weight: bold;
}
.pb-top-bar {
  margin-bottom: 0.6rem;
}
.pb-title {
  letter-spacing: 1px;
}
.pb-stats-info {
  display: flex;
  gap: 12px;
}

.pb-bottom-bar {
  margin-top: auto;
}
.pb-nav-item {
  padding: 2px 6px;
  cursor: crosshair;
  border: 1px solid transparent;
  transition: all 0.2s;
}
.pb-nav-item:hover {
  background-color: rgba(26, 255, 64, 0.15);
}

.pb-middle {
  flex-grow: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.pb-tab-content {
  display: none;
  width: 100%;
  height: 100%;
  animation: pb-glitch 0.4s ease-out;
}

#pb-tab-stat:checked ~ .pb-chassis .pb-title::before {
  content: "SYS_STATUS";
}
#pb-tab-inv:checked ~ .pb-chassis .pb-title::before {
  content: "INVENTORY";
}
#pb-tab-data:checked ~ .pb-chassis .pb-title::before {
  content: "DATA_LINK";
}

#pb-tab-stat:checked ~ .pb-chassis .pb-content-stat,
#pb-tab-inv:checked ~ .pb-chassis .pb-content-inv,
#pb-tab-data:checked ~ .pb-chassis .pb-content-data {
  display: flex;
}

#pb-tab-stat:checked ~ .pb-chassis label[for="pb-tab-stat"],
#pb-tab-inv:checked ~ .pb-chassis label[for="pb-tab-inv"],
#pb-tab-data:checked ~ .pb-chassis label[for="pb-tab-data"] {
  background-color: var(--pip-green);
  color: var(--bg-dark);
  text-shadow: none;
  box-shadow: 0 0 10px var(--pip-glow);
}

.pb-content-stat {
  justify-content: space-between;
  align-items: center;
}
.pb-side-menu {
  display: flex;
  flex-direction: column;
  gap: 5px;
  font-size: 0.6rem;
}
.pb-active-box-static {
  border: 1px solid var(--pip-green);
  padding: 1px 4px;
  box-shadow: inset 0 0 6px var(--pip-glow);
}

.pb-clock {
  display: flex;
  flex-direction: column;
  align-items: center;
}
.pb-block {
  background-color: var(--pip-green);
  border-radius: 4px;
  padding: 4px 10px;
  margin-bottom: 4px;
  box-shadow: 0 0 15px var(--pip-glow);
  animation: pb-pulse 4s infinite alternate;
}
.pb-block .pb-time {
  color: var(--bg-dark);
  font-size: 2.5rem;
  font-weight: bold;
  text-shadow: none;
  filter: drop-shadow(0 0 1px rgba(0, 0, 0, 0.5));
}
.pb-date {
  font-size: 0.8rem;
  font-weight: bold;
  letter-spacing: 1px;
}

.pb-right-menu {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}
.pb-rad-text {
  font-size: 0.6rem;
  font-weight: bold;
  letter-spacing: 1px;
}
.pb-hazard {
  width: 30px;
  height: 30px;
  position: relative;
  background: conic-gradient(
    var(--pip-green) 0deg 60deg,
    transparent 60deg 120deg,
    var(--pip-green) 120deg 180deg,
    transparent 180deg 240deg,
    var(--pip-green) 240deg 300deg,
    transparent 300deg 360deg
  );
  border-radius: 50%;
  animation: pb-spin 8s linear infinite;
  box-shadow: 0 0 15px var(--pip-glow);
}
.pb-hazard-core {
  position: absolute;
  inset: 6px;
  background: var(--bg-dark);
  border-radius: 50%;
}
.pb-hazard-core::after {
  content: "";
  position: absolute;
  inset: 4px;
  background: var(--pip-green);
  border-radius: 50%;
}

.pb-content-inv {
  flex-direction: column;
  font-size: 0.6rem;
  width: 100%;
  justify-content: flex-start;
}
.pb-inventory {
  list-style: none;
  padding: 0;
  margin: 0;
  width: 100%;
}
.pb-inventory li {
  display: flex;
  justify-content: space-between;
  padding: 3px 6px;
  border-bottom: 1px dashed rgba(26, 255, 64, 0.3);
  transition: none;
  cursor: crosshair;
}
.pb-inventory li:hover,
.pb-active-line {
  background-color: var(--pip-green);
  color: var(--bg-dark);
  font-weight: bold;
  text-shadow: none;
  box-shadow: 0 0 10px var(--pip-glow);
  padding: 6px 11px;
}

.pb-content-data {
  justify-content: center;
  align-items: center;
  flex-direction: column;
  gap: 15px;
}
.pb-radar {
  position: relative;
  width: 100px;
  height: 100px;
  background: rgba(26, 255, 64, 0.1);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  box-shadow: inset 0 0 20px var(--pip-glow);
  border: 2px solid var(--pip-green);
}
.pb-radar::before {
  content: "";
  position: absolute;
  inset: 12px;
  background: rgba(26, 255, 64, 0.15);
  border-radius: 50%;
  border: 1px dashed rgba(26, 255, 64, 0.3);
}
.pb-radar::after {
  content: "";
  position: absolute;
  width: 30px;
  height: 30px;
  background: rgba(26, 255, 64, 0.25);
  border-radius: 50%;
  border: 1px solid var(--pip-green);
}
.pb-radar span {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 100%;
  height: 100%;
  background: transparent;
  transform-origin: top left;
  animation: pb-angular 2s linear infinite;
  box-shadow: 6px -100px 40px -30px var(--pip-green);
  border-top: 2px solid var(--pip-green);
  z-index: 2;
}
.pb-blip {
  position: absolute;
  width: 4px;
  height: 4px;
  background: #fff;
  border-radius: 50%;
  top: 22px;
  left: 62px;
  box-shadow:
    0 0 8px #fff,
    0 0 16px var(--pip-green);
  animation: pb-blip-fade 2s infinite;
  z-index: 3;
}

.pb-visualizer {
  display: flex;
  gap: 3px;
  align-items: flex-end;
  height: 15px;
  margin-left: 10px;
}
.pb-bar {
  width: 4px;
  background-color: var(--pip-green);
  animation: pb-bounce 1s infinite alternate;
}
.pb-bar-1 {
  animation-delay: 0.1s;
}
.pb-bar-2 {
  animation-delay: 0.3s;
}
.pb-bar-3 {
  animation-delay: 0s;
}
.pb-bar-4 {
  animation-delay: 0.4s;
}

@keyframes pb-glitch {
  0% {
    opacity: 0;
    filter: contrast(200%);
    transform: translateY(-2px);
    text-shadow:
      3px 0 rgba(255, 0, 0, 0.7),
      -3px 0 rgba(0, 0, 255, 0.7);
  }
  20% {
    opacity: 0.8;
    text-shadow:
      -3px 0 rgba(255, 0, 0, 0.7),
      3px 0 rgba(0, 0, 255, 0.7);
  }
  50% {
    opacity: 0.5;
    filter: contrast(150%) hue-rotate(20deg);
    transform: translateY(2px);
    text-shadow:
      2px 0 rgba(255, 0, 0, 0.7),
      -2px 0 rgba(0, 0, 255, 0.7);
  }
  100% {
    opacity: 1;
    filter: contrast(100%);
    transform: translateY(0);
    text-shadow: 0 0 4px var(--pip-glow);
  }
}

@keyframes pb-crt-scanline {
  0% {
    transform: translateY(-100%);
  }
  100% {
    transform: translateY(800%);
  }
}
@keyframes pb-turn-on {
  0% {
    transform: scale(1, 0.005);
    opacity: 0;
    filter: brightness(10);
  }
  30% {
    transform: scale(1, 0.005);
    opacity: 1;
    filter: brightness(5);
  }
  60% {
    transform: scale(1, 1);
    filter: brightness(2);
  }
  100% {
    transform: scale(1, 1);
    opacity: 1;
    filter: brightness(1);
  }
}
@keyframes pb-angular {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}
@keyframes pb-spin {
  100% {
    transform: rotate(360deg);
  }
}
@keyframes pb-blip-fade {
  0%,
  85% {
    opacity: 0;
  }
  90% {
    opacity: 1;
    transform: scale(1.5);
  }
  100% {
    opacity: 0;
  }
}
@keyframes pb-bounce {
  0% {
    height: 3px;
  }
  100% {
    height: 15px;
  }
}
@keyframes pb-pulse {
  0% {
    box-shadow: 0 0 15px var(--pip-glow);
  }
  100% {
    box-shadow: 0 0 35px var(--pip-glow);
  }
}
@keyframes pb-blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0;
  }
}
@keyframes pb-flicker {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.8;
  }
}
@keyframes pb-pulse-icon-anim {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}

.pb-blink-colon {
  animation: pb-blink 1s step-end infinite;
}
.pb-flicker-text {
  animation: pb-flicker 0.15s infinite;
}
.pb-flicker-fast {
  animation: pb-flicker 0.08s infinite;
}
.pb-pulse-icon {
  animation: pb-pulse-icon-anim 1.5s infinite ease-in-out;
}

@container pb-wrapper (max-width: 600px) {
  .pb-chassis {
    padding: 1.5rem;
    border-radius: 1.5rem;
  }
  .pb-crt {
    border-width: 5px;
  }
  .pb-boot {
    padding: 1.2rem;
  }
  .pb-block .pb-time {
    font-size: 3rem;
  }
  .pb-top-bar,
  .pb-bottom-bar {
    font-size: 0.8rem;
  }
  .pb-side-menu,
  .pb-inventory {
    font-size: 0.85rem;
  }
  .pb-radar {
    width: 130px;
    height: 130px;
  }
  .pb-radar::before {
    inset: 15px;
  }
  .pb-radar::after {
    width: 40px;
    height: 40px;
  }
  .pb-blip {
    top: 30px;
    left: 85px;
  }
  .pb-hazard {
    width: 40px;
    height: 40px;
  }
  .pb-hazard-core {
    inset: 8px;
  }
  .pb-hazard-core::after {
    inset: 4px;
  }
}

@container pb-wrapper (max-width: 450px) {
  .pb-chassis {
    padding: 1rem;
    border-radius: 1rem;
  }
  .pb-crt {
    border-width: 4px;
  }
  .pb-boot {
    padding: 0.8rem;
  }
  .pb-block {
    padding: 4px 8px;
  }
  .pb-block .pb-time {
    font-size: 1.5rem;
  }
  .pb-date {
    font-size: 0.7rem;
    letter-spacing: 1px;
  }
  .pb-top-bar {
    margin-bottom: 0.8rem;
  }
  .pb-top-bar,
  .pb-bottom-bar {
    font-size: 0.6rem;
  }
  .pb-stats-info {
    gap: 5px;
  }
  .pb-flexible {
    margin: 0 5px;
  }
  .pb-nav-item {
    padding: 2px 4px;
  }
  .pb-side-menu {
    font-size: 0.6rem;
    gap: 5px;
  }
  .pb-inventory {
    font-size: 0.65rem;
  }
  .pb-rad-text {
    font-size: 0.6rem;
  }
  .pb-radar {
    width: 100px;
    height: 100px;
  }
  .pb-radar::before {
    inset: 12px;
  }
  .pb-radar::after {
    width: 30px;
    height: 30px;
  }
  .pb-blip {
    top: 20px;
    left: 65px;
    width: 4px;
    height: 4px;
  }
  .pb-hazard {
    width: 30px;
    height: 30px;
    box-shadow: 0 0 10px var(--pip-glow);
  }
  .pb-hazard-core {
    inset: 6px;
  }
  .pb-hazard-core::after {
    inset: 3px;
  }
}

.pda-device {
  --pda-w: 300px;
  --pda-h: 400px;

  --pda-case-top: #676c73;
  --pda-case-bot: #2b2f35;
  --pda-lcd-bg: #f3d9a3;
  --pda-lcd-ink: #3a2700;
  --pda-lcd-dim: #a38241;
  --pda-lcd-line: rgba(0, 0, 0, 0.06);
  --pda-dock: #242b30;

  width: var(--pda-w);
  height: var(--pda-h);
  position: relative;
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono",
    monospace;
  color: var(--pda-lcd-ink);
}

.pda-tab,
.pda-backlight {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.pda-bezel {
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, var(--pda-case-top), var(--pda-case-bot));
  border-radius: 16px;
  box-shadow:
    inset 0 2px 0 rgba(255, 255, 255, 0.15),
    inset 0 -2px 0 rgba(0, 0, 0, 0.28),
    0 16px 28px rgba(0, 0, 0, 0.35);
  padding: 12px 10px 12px 10px;
}

.pda-screws {
  position: absolute;
  inset: 6px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-template-rows: 1fr 1fr;
  pointer-events: none;
}
.pda-screws .pda-screw {
  width: 12px;
  height: 12px;
}
.pda-screws .pda-screw:nth-child(1) {
  justify-self: start;
  align-self: start;
}
.pda-screws .pda-screw:nth-child(2) {
  justify-self: end;
  align-self: start;
}
.pda-screws .pda-screw:nth-child(3) {
  justify-self: start;
  align-self: end;
}
.pda-screws .pda-screw:nth-child(4) {
  justify-self: end;
  align-self: end;
}

.pda-knob {
  position: absolute;
  bottom: 10px;
  left: 50%;
  transform: translateX(-50%);
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: radial-gradient(circle at 35% 35%, #7b828a, #444a52);
  box-shadow:
    inset 0 3px 5px rgba(255, 255, 255, 0.18),
    inset 0 -3px 5px rgba(0, 0, 0, 0.5),
    0 6px 10px rgba(0, 0, 0, 0.3);
  cursor: pointer;
  user-select: none;
  display: grid;
  place-items: center;
}
.pda-knob-cap {
  width: 8px;
  height: 8px;
  border-radius: 2px;
  background: #14181d;
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.15),
    0 -1px 0 rgba(0, 0, 0, 0.6);
}

.pda-led {
  position: absolute;
  top: 15px;
  left: 50%;
  transform: translateX(-50%);
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #4a1010;
  box-shadow:
    inset 0 0 2px #ff5b5b,
    0 0 0 1px #100;
}
.pda-led::after {
  content: "";
  position: absolute;
  left: -2px;
  top: -2px;
  right: -2px;
  bottom: -2px;
  border-radius: 50%;
  box-shadow: 0 0 0 0 rgba(255, 70, 70, 0);
  pointer-events: none;
}
#pda-tab-map.pda-tab:checked ~ .pda-bezel .pda-led {
  background: #ff3a3a;
  box-shadow:
    inset 0 0 2px #ffd5d5,
    0 0 6px 2px rgba(255, 60, 60, 0.45);
  animation: pda-led 1s steps(2, end) infinite;
}
#pda-tab-map.pda-tab:checked ~ .pda-bezel .pda-led::after {
  animation: pda-beam 1.6s ease-out infinite;
}
@keyframes pda-led {
  50% {
    filter: brightness(1.3);
  }
}
@keyframes pda-beam {
  0% {
    box-shadow: 0 0 0 0 rgba(255, 70, 70, 0.35);
  }
  100% {
    box-shadow: 0 0 0 10px rgba(255, 70, 70, 0);
  }
}

.pda-screen {
  position: absolute;
  left: 10px;
  right: 10px;
  top: 40px;
  bottom: 48px;
  background: var(--pda-lcd-bg);
  border-radius: 9px;
  overflow: hidden;
  box-shadow:
    inset 0 2px 0 rgba(255, 255, 255, 0.5),
    inset 0 -2px 0 rgba(0, 0, 0, 0.12),
    0 0 0 2px #101010;
}
.pda-screen::before {
  content: "";
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
      0deg,
      transparent 0 1px,
      var(--pda-lcd-line) 1px 2px
    ),
    repeating-linear-gradient(
      90deg,
      transparent 0 1px,
      rgba(0, 0, 0, 0.03) 1px 2px
    );
  pointer-events: none;
}
.pda-screen::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.12),
      transparent 45%
    ),
    radial-gradient(
      60% 40% at 10% 0%,
      rgba(255, 255, 255, 0.16),
      transparent 60%
    );
  mix-blend-mode: screen;
  pointer-events: none;
}

.pda-statusbar {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 20px;
  display: grid;
  grid-template-columns: 1fr auto;
  align-items: center;
  padding: 0 6px;
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.2), transparent);
  font-weight: 900;
  font-size: 11px;
}
.pda-logo {
  display: grid;
  grid-auto-flow: column;
  gap: 4px;
  align-items: center;
}
.pda-blink {
  width: 5px;
  height: 10px;
  background: var(--pda-lcd-ink);
  display: inline-block;
  animation: pda-blink 1s steps(2, end) infinite;
}
@keyframes pda-blink {
  50% {
    opacity: 0;
  }
}
.pda-ind {
  display: grid;
  grid-auto-flow: column;
  gap: 6px;
  align-items: center;
}
.pda-sig {
  display: grid;
  grid-auto-flow: column;
  gap: 2px;
}
.pda-sb {
  width: 3px;
  background: var(--pda-lcd-ink);
  display: inline-block;
}
.pda-sb--1 {
  height: 5px;
}
.pda-sb--2 {
  height: 8px;
}
.pda-sb--3 {
  height: 10px;
}
.pda-bat {
  display: grid;
  grid-auto-flow: column;
  gap: 2px;
  align-items: center;
}
.pda-bb {
  width: 16px;
  height: 9px;
  border: 1px solid var(--pda-lcd-ink);
  position: relative;
}
.pda-bf {
  position: absolute;
  left: 1px;
  top: 1px;
  bottom: 1px;
  width: 10px;
  background: var(--pda-lcd-ink);
  animation: pda-bat 3s steps(3, end) infinite;
}
@keyframes pda-bat {
  0%,
  100% {
    width: 10px;
  }
  50% {
    width: 14px;
  }
}
.pda-bt {
  width: 2px;
  height: 5px;
  background: var(--pda-lcd-ink);
}
.pda-clk {
  font-weight: 900;
}

.pda-boot {
  position: absolute;
  inset: 20px 0 26px 0;
  padding: 8px 8px 0;
  background: linear-gradient(
    180deg,
    rgba(255, 255, 255, 0.25),
    rgba(255, 255, 255, 0.12)
  );
  animation: pda-boot-fade 2.7s 0.2s ease forwards;
  z-index: 3;
}
@keyframes pda-boot-fade {
  0% {
    opacity: 1;
  }
  85% {
    opacity: 1;
  }
  100% {
    opacity: 0;
    pointer-events: none;
  }
}
.pda-bline {
  color: var(--pda-lcd-ink);
  font-weight: 900;
  font-size: 11px;
  white-space: nowrap;
  overflow: hidden;
}
.pda-bline--1 {
  max-width: 0;
  animation: pda-type 0.85s steps(22, end) forwards;
}
.pda-bline--2 {
  max-width: 0;
  animation: pda-type 0.6s 0.85s steps(20, end) forwards;
}
.pda-bline--3 {
  max-width: 0;
  animation: pda-type 0.6s 1.45s steps(18, end) forwards;
}
.pda-bline--err {
  margin: 2px 0;
  padding: 2px 4px;
  border: 1px dashed var(--pda-lcd-ink);
  background: rgba(0, 0, 0, 0.06);
  animation: pda-errflash 0.9s 2.05s steps(2, end) 2;
}
@keyframes pda-errflash {
  50% {
    filter: invert(1);
  }
}
.pda-bprog {
  margin-top: 2px;
  height: 7px;
  border: 1px solid var(--pda-lcd-ink);
  position: relative;
}
.pda-bfill {
  position: absolute;
  inset: 1px;
  width: 0;
  background: var(--pda-lcd-ink);
  animation: pda-fill 1.1s 2.05s steps(12, end) forwards;
}
@keyframes pda-fill {
  to {
    width: calc(100% - 2px);
  }
}
.pda-bline--5 {
  position: absolute;
  bottom: 2px;
  left: 8px;
  opacity: 0.95;
}
@keyframes pda-type {
  to {
    max-width: 100%;
  }
}

.pda-viewport {
  position: absolute;
  inset: 20px 0 26px 0;
  overflow: hidden;
}
.pda-apps {
  position: absolute;
  top: 0;
  left: 0;
  width: 400%;
  height: 100%;
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  transition: transform 0.48s cubic-bezier(0.2, 0.7, 0.2, 1);
}

.pda-app {
  position: relative;
  padding: 6px;
  display: grid;
  grid-template-rows: auto 1fr auto;
  gap: 6px;
  background:
    radial-gradient(
        3px 3px at 22% 32%,
        rgba(0, 0, 0, 0.03) 35%,
        transparent 40%
      )
      0 0/10px 10px,
    radial-gradient(
        3px 3px at 70% 60%,
        rgba(0, 0, 0, 0.03) 35%,
        transparent 40%
      )
      0 0/12px 12px,
    transparent;
}
.pda-title {
  font-weight: 900;
  font-size: 11px;
  text-transform: uppercase;
  border-bottom: 1px dashed rgba(0, 0, 0, 0.15);
  padding-bottom: 3px;
}

.pda-box {
  border: 1px solid rgba(0, 0, 0, 0.25);
  background: linear-gradient(
    180deg,
    rgba(255, 255, 255, 0.28),
    rgba(255, 255, 255, 0.12)
  );
  padding: 6px;
  border-radius: 2px;
  display: grid;
  gap: 4px;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.55),
    inset 0 -1px 0 rgba(0, 0, 0, 0.08);
}
.pda-box--map {
  display: grid;
  grid-template-rows: auto auto;
  gap: 6px;
}

.pda-kv {
  display: grid;
  grid-template-columns: 58px 1fr;
  gap: 4px;
  font-weight: 900;
  font-size: 11px;
}
.pda-k {
  color: var(--pda-lcd-dim);
}
.pda-v {
  color: var(--pda-lcd-ink);
}

.pda-prog {
  position: relative;
  height: 16px;
  margin-top: 2px;
}
.pda-trk {
  position: absolute;
  inset: 3px;
  border: 1px solid var(--pda-lcd-ink);
}
.pda-fill {
  position: absolute;
  left: 4px;
  top: 4px;
  bottom: 4px;
  width: 0;
  background: var(--pda-lcd-ink);
  animation: pda-prog 1.5s 0.2s steps(28, end) forwards;
}
.pda-ticks {
  position: absolute;
  inset: 3px;
  background: repeating-linear-gradient(
    90deg,
    transparent 0 7px,
    rgba(0, 0, 0, 0.14) 7px 8px
  );
  pointer-events: none;
}
.pda-plabel {
  position: absolute;
  right: 6px;
  top: 0;
  bottom: 0;
  display: grid;
  align-items: center;
  font-weight: 900;
  font-size: 10px;
}
@keyframes pda-prog {
  to {
    width: calc(60% - 6px);
  }
}

.pda-timeline {
  margin-top: 5px;
  display: grid;
  gap: 4px;
}
.pda-row {
  display: grid;
  grid-template-columns: 8px 1fr;
  gap: 6px;
  align-items: center;
  font-weight: 900;
  font-size: 10px;
}
.pda-row--done .pda-rt {
  color: var(--pda-lcd-dim);
}
.pda-dot {
  width: 6px;
  height: 6px;
  background: var(--pda-lcd-ink);
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.18) inset;
}
.pda-dot--truck {
  display: grid;
  place-items: center;
  background: transparent;
  border: 1px solid var(--pda-lcd-ink);
}
.pda-truck {
  width: 9px;
  height: 9px;
}
.pda-tc,
.pda-tb,
.pda-tw {
  fill: var(--pda-lcd-ink);
}

.pda-cursor {
  position: absolute;
  right: 6px;
  bottom: 32px;
  font-weight: 900;
  animation: pda-cursor 1.05s steps(2, end) infinite;
}
@keyframes pda-cursor {
  50% {
    opacity: 0;
  }
}

.pda-map {
  width: 100%;
  height: 72px;
  image-rendering: pixelated;
}
.pda-px {
  fill: var(--pda-lcd-ink);
}
.pda-ping {
  fill: none;
  stroke: var(--pda-lcd-ink);
  stroke-width: 1;
  animation: pda-ping 1.7s ease-out infinite;
  transform-origin: center;
}
@keyframes pda-ping {
  0% {
    r: 0;
    opacity: 1;
  }
  70% {
    r: 12;
    opacity: 0.2;
  }
  100% {
    r: 12;
    opacity: 0;
  }
}

.pda-legend {
  display: grid;
  gap: 2px;
}
.pda-scan {
  position: absolute;
  left: 6px;
  right: 6px;
  bottom: 36px;
  height: 7px;
  border: 1px solid var(--pda-lcd-ink);
  overflow: hidden;
}
.pda-scan::before {
  content: "";
  position: absolute;
  inset: 1px;
  background: repeating-linear-gradient(
    90deg,
    var(--pda-lcd-ink) 0 6px,
    transparent 6px 10px
  );
  animation: pda-scan 1.1s linear infinite;
}
@keyframes pda-scan {
  to {
    transform: translateX(10px);
  }
}

.pda-scroll {
  max-height: 132px;
  overflow: auto;
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.pda-scroll::-webkit-scrollbar {
  display: none;
}
.pda-tip {
  text-align: center;
  font-size: 10px;
  color: var(--pda-lcd-dim);
  margin-top: 5px;
}

.pda-meter {
  display: grid;
  grid-template-columns: 34px 1fr 26px;
  gap: 6px;
  align-items: center;
}
.pda-ml {
  font-weight: 900;
  font-size: 10px;
  color: var(--pda-lcd-dim);
}
.pda-mb {
  height: 9px;
  border: 1px solid var(--pda-lcd-ink);
  position: relative;
  overflow: hidden;
}
.pda-mf {
  position: absolute;
  inset: 1px;
  background: repeating-linear-gradient(
    90deg,
    var(--pda-lcd-ink) 0 6px,
    transparent 6px 8px
  );
}
.pda-mf--cpu {
  width: 42%;
  animation: pda-wob 2.3s ease-in-out infinite;
}
.pda-mf--mem {
  width: 68%;
  animation: pda-wob 3s ease-in-out infinite;
}
.pda-mf--sto {
  width: 55%;
  animation: pda-wob 2.6s ease-in-out infinite;
}
@keyframes pda-wob {
  50% {
    transform: translateX(2px);
  }
}
.pda-mv {
  justify-self: end;
  font-weight: 900;
  font-size: 10px;
}

.pda-diag {
  margin-top: 5px;
  border: 1px dashed rgba(0, 0, 0, 0.18);
  padding: 6px;
}
.pda-drow {
  font-weight: 900;
  font-size: 10px;
  display: grid;
  grid-auto-flow: column;
  justify-content: start;
  gap: 6px;
}
.pda-caret {
  font-weight: 900;
}

.pda-dock {
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 26px;
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  background: linear-gradient(180deg, rgba(0, 0, 0, 0.25), rgba(0, 0, 0, 0.5));
  border-top: 1px solid #0f0f0f;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.1);
}
.pda-db {
  display: grid;
  place-items: center;
  cursor: pointer;
  transition: filter 0.15s;
}
.pda-db:hover {
  filter: brightness(1.1);
}
.pda-ico {
  width: 14px;
  height: 14px;
}
.pda-st {
  stroke: var(--pda-lcd-ink);
  stroke-width: 1.7;
  fill: none;
}

#pda-tab-status.pda-tab:checked ~ .pda-bezel .pda-apps {
  transform: translateX(0%);
}
#pda-tab-map.pda-tab:checked ~ .pda-bezel .pda-apps {
  transform: translateX(-25%);
}
#pda-tab-info.pda-tab:checked ~ .pda-bezel .pda-apps {
  transform: translateX(-50%);
}
#pda-tab-sys.pda-tab:checked ~ .pda-bezel .pda-apps {
  transform: translateX(-75%);
}

#pda-tab-status.pda-tab:checked
  ~ .pda-bezel
  .pda-dock
  .pda-db:nth-child(1)::after,
#pda-tab-map.pda-tab:checked
  ~ .pda-bezel
  .pda-dock
  .pda-db:nth-child(2)::after,
#pda-tab-info.pda-tab:checked
  ~ .pda-bezel
  .pda-dock
  .pda-db:nth-child(3)::after,
#pda-tab-sys.pda-tab:checked
  ~ .pda-bezel
  .pda-dock
  .pda-db:nth-child(4)::after {
  content: "";
  width: 60%;
  height: 2px;
  background: var(--pda-lcd-ink);
  display: block;
  border-radius: 1px;
  animation: pda-ul 0.9s steps(3, end) infinite;
}
@keyframes pda-ul {
  50% {
    transform: translateY(-1px);
  }
}

.pda-backlight:checked ~ .pda-bezel .pda-screen {
  filter: brightness(1.12) contrast(1.05) saturate(1.06);
}
.pda-backlight:not(:checked) ~ .pda-bezel .pda-screen {
  filter: brightness(0.88) contrast(0.95) saturate(0.92);
}

.el-lid {
  background-color: rgb(0, 0, 0);
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  box-shadow: 0 9px 0 2px rgba(0, 0, 0, 0.2);
  width: 150px;
  height: 150px;
}

.el-eye {
  background-color: #fffcf4;
  border-radius: 50%;
  transform: translate3d(0, 0, 0) rotate(90deg);
  width: 120px;
  height: 120px;
  animation: el-eye-anim 5s infinite;
}

@keyframes el-eye-anim {
  12%,
  25% {
    width: 100px;
    height: 110px;
  }

  37%,
  50% {
    width: 60px;
    height: 130px;
  }

  63%,
  75% {
    width: 100px;
    height: 103px;
  }

  87% {
    width: 100px;
    height: 100px;
  }
}

.el-cornea {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background-color: rgb(0, 0, 0);
  border-radius: 50%;
  width: 50px;
  height: 50px;
  animation: el-eye-color 5s infinite;
}

@keyframes el-eye-color {
  63%, 75% {
    background-color: rgb(137, 1, 1);
  }
}

.el-white-pupil {
  position: absolute;
  top: 70%;
  left: 10%;
  border-radius: 50%;
  background-color: #fffcf4;
  width: 20px;
  height: 20px;
}

.tdr-main-wrap {
