.btn-wrapper {
  --rad: 32px;
  --color-wrapper-border: #fff;
  --color-btn-bg: #f00;
  --color-btn-text: #000;
  --color-btn-text-shadow: #fff;
  --color-btn-inset-shadow: #558;
  --color-layer-a: #fff;
  --color-layer-b: #00f;
  --color-overlay-text: #000;
  --color-overlay-glow: #fff;
  --color-overlay-shadow: #0004;
  --color-overlay-highlight: #fff5;

  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: clip;
  overflow-clip-margin: 4px;

  border: 2px solid var(--color-wrapper-border);
  border-radius: var(--rad);

  font-family: "Inter", sans-serif;
  font-size: 1.5rem;
  font-weight: 600;

  filter: saturate(0.65) brightness(1.8);
}

.gradient-btn {
  position: relative;
  z-index: -1;

  padding: 12px 36px;
  border: none;
  border-radius: var(--rad);

  font-family: inherit;
  font-size: inherit;
  font-weight: inherit;
  letter-spacing: 0.15rem;

  color: var(--color-btn-text);
  background-color: var(--color-btn-bg);
  background-size: 200% 200%;
  box-shadow: inset 0 0 10px 9px var(--color-btn-inset-shadow);
  text-shadow: 0 1px 3px var(--color-btn-text-shadow);

  cursor: pointer;
  mix-blend-mode: color-dodge;
  transition:
    color 0.3s ease,
    text-shadow 0.3s ease;
}

.gradient-btn::after {
  content: "";
  position: absolute;
  pointer-events: none;

  left: 0;
  top: 0;
  width: 100%;
  height: 100%;

  border-radius: var(--rad);
  background-size: 200% 200%;
  mix-blend-mode: difference;
  z-index: 1;
}

.gradient-layer {
  position: absolute;
  pointer-events: none;

  left: -160px;
  width: 500%;
  aspect-ratio: 1;

  background: radial-gradient(
    ellipse at 65% 180%,
    var(--color-layer-a),
    var(--color-layer-b),
    var(--color-layer-a),
    var(--color-layer-b),
    var(--color-layer-a),
    var(--color-layer-b),
    var(--color-layer-a),
    var(--color-layer-b),
    var(--color-layer-a),
    var(--color-layer-b),
    var(--color-layer-a)
  );

  mix-blend-mode: difference;
  animation: rotate 8s linear infinite;
}

.gradient-layer:last-child {
  mix-blend-mode: color-dodge;
}

@keyframes rotate {
  0% {
    transform: rotate(0deg);
  }

  100% {
    transform: rotate(360deg);
  }
}

.text-overlay {
  position: absolute;
  pointer-events: none;
  z-index: 2;

  padding: 12px 36px;
  border-radius: var(--rad);

  font-family: inherit;
  font-size: inherit;
  font-weight: inherit;
  letter-spacing: 0.15rem;

  color: var(--color-overlay-text);
  text-shadow: 0 0 4px var(--color-overlay-glow);
  box-shadow:
    inset 0 -4px 4px 0 var(--color-overlay-shadow),
    inset 0 4px 4px 0 var(--color-overlay-highlight);

  mix-blend-mode: multiply;
  transition: transform 0.3s ease;
  animation: opacityPulse 5s ease infinite;
}

.btn-wrapper:hover {
  .text-overlay {
    transform: scale(1.1);
  }

  .gradient-btn {
    color: #0000;
    text-shadow: 0 0 0 #0000;
  }
}

.btn-wrapper:active {
  .text-overlay {
    transform: scale(0.95);
  }

  .gradient-btn {
    color: #0000;
    text-shadow: 0 0 0 #0000;
  }
}

