.mp-progress-bar {
  width: 100%;
  height: 4px;
  background-color: rgba(255, 255, 255, 0.1);
  border-radius: 2px;
  position: relative;
  overflow: hidden;
}

.mp-progress-fill {
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, #00c6ff, #0072ff);
  border-radius: 2px;
  animation: mp-progress-anim 45s linear infinite;
  animation-play-state: running;
}

.mp-progress-handle {
  position: absolute;
  top: 50%;
  left: 0%;
  transform: translate(-50%, -50%);
  width: 10px;
  height: 10px;
  background-color: white;
  border-radius: 50%;
  box-shadow: 0 0 6px rgba(0, 0, 0, 0.5);
  animation: mp-handle-anim 45s linear infinite;
  animation-play-state: running;
}

.mp-button-row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
}

.mp-control-button {
  margin-top: 2%;
  width: 52px;
  height: 52px;
  border-radius: 50%;
  border: none;
  background: none;
  display: flex;
  justify-content: center;
  align-items: center;
  cursor: pointer;
  transition:
    background 0.2s,
    transform 0.2s;
  color: #fff;
}

.mp-control-button.mp-play-pause-button:hover,
.mp-control-button.mp-d:hover {
  background: rgba(255, 255, 255, 0.1);
  transform: scale(1.05);
}

.mp-main-control-btns {
  justify-content: center;
  align-items: center;
  display: flex;
  margin-left: 10%;
  gap: 20%;
}

.mp-play-pause-button .mp-icon-pause {
  display: none;
}

#mp-play-toggle:checked ~ .mp-track-info .mp-volume-bars .mp-bar {
  animation-play-state: paused;
}
#mp-play-toggle:checked ~ .mp-playback-controls .mp-progress-fill,
#mp-play-toggle:checked ~ .mp-playback-controls .mp-progress-handle {
  animation-play-state: paused;
}
.mp-card:has(#mp-play-toggle:checked) .mp-time-info .mp-current-time::before,
.mp-card:has(#mp-play-toggle:checked) .mp-time-info .mp-remaining-time::before {
  animation-play-state: paused;
}
#mp-play-toggle:checked ~ .mp-playback-controls .mp-play-pause-button .mp-icon-play {
  display: block;
}
#mp-play-toggle:checked ~ .mp-playback-controls .mp-play-pause-button .mp-icon-pause {
  display: none;
}

#mp-play-toggle:not(:checked) ~ .mp-playback-controls .mp-play-pause-button .mp-icon-play {
  display: none;
}
#mp-play-toggle:not(:checked) ~ .mp-playback-controls .mp-play-pause-button .mp-icon-pause {
  display: block;
}

@keyframes mp-progress-anim {
  from {
    width: 0;
  }
  to {
    width: 100%;
  }
}

@keyframes mp-handle-anim {
  from {
    left: 0%;
  }
  to {
    left: 100%;
  }
}

.rc-receipt {
  width: 250px;
  background: white;
  border: 2px dashed #ccc;
  padding: 15px;
  border-radius: 8px;
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
}

.rc-shop-name {
  font-size: 1.2rem;
  font-weight: bold;
  text-align: center;
  margin-bottom: 10px;
}

.rc-info {
  text-align: center;
  font-size: 0.85rem;
  margin-bottom: 15px;
}

.rc-receipt .rc-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 15px;
  font-size: 0.85rem;
}

.rc-receipt .rc-table th,
.rc-receipt .rc-table td {
  padding: 4px;
  text-align: left;
  border-bottom: 1px solid #eee;
}

.rc-total {
  display: flex;
  justify-content: space-between;
  font-size: 1rem;
  font-weight: bold;
  margin-bottom: 15px;
}

.rc-barcode {
  display: flex;
  justify-content: center;
  margin-top: 15px;
}

.rc-thanks {
  font-size: 0.85rem;
  text-align: center;
  margin-top: 10px;
}

.jo-columns {
  width: 19em;
  position: relative;
  border-radius: 20px;
  padding: 35px;
  border: 2px solid black;
  transition: all 0.4s;
}

.jo-columns:hover {
  box-shadow: 4px 4px 0 1px rgba(0, 0, 0);
}

.jo-dots {
  position: absolute;
  right: 15px;
