.cc-card {
  max-width: 360px;
  width: 90%;
  padding: 20px;
  border-radius: 35px;
  background: #000;
  color: #fff;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
}

.cc-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}
.cc-logo {
  font-weight: bold;
  font-size: 1.2em;
}
.cc-open {
  font-size: 0.85em;
  color: #888;
  cursor: pointer;
  transition: all 0.3s ease;
}
.cc-open:hover {
  color: #fff;
}

.cc-switch {
  position: relative;
  display: flex;
  background: #222;
  border-radius: 20px;
  padding: 4px;
  gap: 8px;
  margin-bottom: 16px;
  user-select: none;
  border: none;
}
.cc-switch input {
  display: none;
}
.cc-switch label {
  flex: 1;
  text-align: center;
  padding: 8px 0;
  border-radius: 16px;
  cursor: pointer;
  color: #cccccc;
  font-weight: 500;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  transition: color 0.3s;
  font-size: 0.9em;
}
.cc-switch input:checked + label {
  color: #ffffff;
}

.cc-slider {
  position: absolute;
  top: 4px;
  bottom: 4px;
  width: calc((100% - 24px) / 4);
  background: rgba(255, 255, 255, 0.4);
  -webkit-backdrop-filter: blur(1px);
  backdrop-filter: blur(0.5px);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 16px;
  z-index: 1;
  transition: transform 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);
  box-shadow:
    0 4px 8px rgba(0, 0, 0, 0.4),
    inset 0 -2px 4px rgba(255, 255, 255, 0.2);
}
.cc-switch input:hover + label {
  color: #ffffff;
}
#cc-bitcoin:checked ~ .cc-slider {
  transform: translateX(0%);
}
#cc-ethereum:checked ~ .cc-slider {
  transform: translateX(105%);
}
#cc-solana:checked ~ .cc-slider {
  transform: translateX(214%);
}
#cc-tether:checked ~ .cc-slider {
  transform: translateX(323%);
}

.cc-price-infos {
  margin-bottom: 16px;
}
.cc-price-info .cc-price {
  font-size: 1.6em;
  font-weight: bold;
  margin-bottom: 4px;
}
.cc-price-info .cc-stats {
  display: flex;
  justify-content: space-between;
  font-size: 0.9em;
}
.cc-price-info .cc-change {
  color: #0f0;
  font-weight: bold;
}

.cc-chart {
  height: 90px;
  background: #1b1b1b;
  border-radius: 12px;
  position: relative;
  overflow: hidden;
  width: 100%;
}
.cc-chart svg {
  width: 100%;
  height: 100%;
  display: none;
  transform: translateX(2px) scale(1.05);
}
.cc-chart path {
  stroke: #0f0;
  stroke-width: 0.7;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-dasharray: 500;
  stroke-dashoffset: 500;
  animation: cc-draw 3s forwards;
  fill: rgba(0, 255, 0, 0.2);
}
@keyframes cc-draw {
  to {
    stroke-dashoffset: 0;
  }
}

.cc-card:has(#cc-bitcoin:checked) .cc-chart #cc-chart-bitcoin,
.cc-card:has(#cc-ethereum:checked) .cc-chart #cc-chart-ethereum,
.cc-card:has(#cc-solana:checked) .cc-chart #cc-chart-solana,
.cc-card:has(#cc-tether:checked) .cc-chart #cc-chart-tether {
  display: block;
}

.cc-price-info {
  display: none;
}
.cc-card:has(#cc-bitcoin:checked) .cc-price-info.cc-bitcoin-info,
.cc-card:has(#cc-ethereum:checked) .cc-price-info.cc-ethereum-info,
.cc-card:has(#cc-solana:checked) .cc-price-info.cc-solana-info,
.cc-card:has(#cc-tether:checked) .cc-price-info.cc-tether-info {
  display: block;
}

