}

.ms-type {
  position: absolute;
  top: 10%;
  left: 5%;
  display: flex;
  flex-direction: column;
  z-index: 5;
}

.ms-huge {
  font-family: var(--ms-font-display);
  font-size: 3.5rem;
  line-height: 0.8;
  letter-spacing: -0.04em;
  color: var(--ms-text-main);
  text-transform: uppercase;
  mix-blend-mode: exclusion;
  position: relative;
  transition: color 0.6s ease;
}

.ms-word-2 {
  margin-left: 10%;
  color: transparent;
  -webkit-text-stroke: 2px var(--ms-text-main);
}

.ms-tape {
  position: absolute;
  top: 50%;
  left: -30%;
  width: 160%;
  background: var(--ms-accent);
  color: var(--ms-bg-inner);
  transform: rotate(-12deg) scale(1.05);
  padding: 0.6rem 0;
  font-family: var(--ms-font-mono);
  font-size: 0.8rem;
  font-weight: 900;
  white-space: nowrap;
  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
  z-index: 20;
  display: flex;
  overflow: hidden;
  transition: all 0.6s ease;
}

.ms-tape-scroll {
  display: flex;
  width: max-content;
  animation: ms-scroll 10s linear infinite;
}

.ms-tape-scroll span {
  padding-right: 1rem;
}

@keyframes ms-scroll {
  to {
    transform: translateX(-50%);
  }
}

.ms-footer {
  position: absolute;
  bottom: 5%;
  left: 5%;
  right: 5%;
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  z-index: 5;
  border-top: 2px solid var(--ms-text-main);
  padding-top: 0.6rem;
  transition: border-color 0.6s ease;
}

.ms-barcode {
  width: 50px;
  height: 25px;
  background: repeating-linear-gradient(
    to right,
    var(--ms-text-main) 0,
    var(--ms-text-main) 2px,
    transparent 2px,
    transparent 4px,
    var(--ms-text-main) 4px,
    var(--ms-text-main) 6px,
    transparent 6px,
    transparent 10px,
    var(--ms-text-main) 10px,
    var(--ms-text-main) 11px,
    transparent 11px,
    transparent 15px,
    var(--ms-text-main) 15px,
    var(--ms-text-main) 19px,
    transparent 19px,
    transparent 22px
  );
  transition: background 0.6s ease;
}

.ms-manifesto {
  max-width: 65%;
  text-align: right;
  color: var(--ms-text-main);
  transition: color 0.6s ease;
}

.ms-manifesto p {
  margin: 0;
}

.ms-vol {
  font-family: var(--ms-font-mono);
  font-weight: bold;
  font-size: 0.55rem;
  margin-bottom: 0.2rem !important;
  text-transform: uppercase;
}

.ms-desc {
  font-size: 0.5rem;
  line-height: 1.3;
  opacity: 0.8;
}

.ms-rebel-toggle:checked ~ .ms-stage .ms-orb {
  animation: ms-pulse-acid 3s ease-in-out infinite alternate;
  mix-blend-mode: screen;
}

.ms-rebel-toggle:checked ~ .ms-stage .ms-huge {
  text-shadow:
    4px 4px 0px var(--ms-accent),
    -2px -2px 0px #00ffff;
  mix-blend-mode: normal;
}

@keyframes ms-pulse-acid {
  0% {
    transform: scale(1) translate(0, 0);
    opacity: 0.6;
    filter: blur(10px);
  }
  100% {
    transform: scale(1.2) translate(-10%, 10%);
    opacity: 1;
    filter: blur(20px);
  }
}

.chk-bounce {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  user-select: none;
  font-size: 15px;
  color: #e4e4e7;
}

.chk-bounce input { display: none; }

.chk-bounce__box {
  position: relative;
  width: 22px;
  height: 22px;
  border: 2px solid #52525b;
  border-radius: 6px;
  transition: all 0.2s ease;
  background: transparent;
}

.chk-bounce__box::after {
  content: '';
  position: absolute;
  left: 6px;
  top: 2px;
  width: 5px;
  height: 11px;
  border: solid #fff;
  border-width: 0 2px 2px 0;
  transform: rotate(45deg) scale(0);
  transition: transform 0.2s ease;
}

.chk-bounce input:checked + .chk-bounce__box {
  background: #7c3aed;
  border-color: #7c3aed;
  animation: bounce 0.4s ease;
}

.chk-bounce input:checked + .chk-bounce__box::after {
  transform: rotate(45deg) scale(1);
}

@keyframes bounce {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.15); }
}

.chk-glow {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  user-select: none;
  font-size: 15px;
  color: #e4e4e7;
}

.chk-glow input { display: none; }

.chk-glow__box {
  position: relative;
  width: 24px;
  height: 24px;
  border: 2px solid #52525b;
  border-radius: 8px;
  background: transparent;
