  background: red;
  display: flex;
  width: 30px;
  height: 30px;
  position: relative;
  align-items: center;
  justify-content: center;
  left: 8px;
  margin: 0.8rem 4px;
  transform: rotate(45deg);
  animation-delay: 2s;
}

.ldr-love::before, .ldr-love::after {
  content: "";
  position: absolute;
  width: 30px;
  height: 30px;
