.ds-loader {
  --ds-c1: #673b14;
  --ds-c2: #f8b13b;
  width: 40px;
  height: 80px;
  border-top: 4px solid var(--ds-c1);
  border-bottom: 4px solid var(--ds-c1);
  background: linear-gradient(90deg, var(--ds-c1) 2px, var(--ds-c2) 0 5px, var(--ds-c1) 0) 50%/7px 8px no-repeat;
  display: grid;
  overflow: hidden;
  animation: ds-l5-0 2s infinite linear;
}

.ds-loader::before,
.ds-loader::after {
  content: "";
  grid-area: 1/1;
  width: 75%;
  height: calc(50% - 4px);
  margin: 0 auto;
  border: 2px solid var(--ds-c1);
  border-top: 0;
  box-sizing: content-box;
  border-radius: 0 0 40% 40%;
  -webkit-mask: linear-gradient(#000 0 0) bottom/4px 2px no-repeat,
    linear-gradient(#000 0 0);
  -webkit-mask-composite: destination-out;
  mask-composite: exclude;
  background: linear-gradient(var(--ds-d, 0deg), var(--ds-c2) 50%, #0000 0) bottom /100% 205%,
    linear-gradient(var(--ds-c2) 0 0) center/0 100%;
  background-repeat: no-repeat;
  animation: inherit;
  animation-name: ds-l5-1;
}

.ds-loader::after {
  transform-origin: 50% calc(100% + 2px);
  transform: scaleY(-1);
  --ds-s: 3px;
  --ds-d: 180deg;
}

@keyframes ds-l5-0 {
  80% {
    transform: rotate(0);
  }

  100% {
    transform: rotate(0.5turn);
  }
}

@keyframes ds-l5-1 {
  10%, 70% {
    background-size: 100% 205%, var(--ds-s, 0) 100%;
  }

  70%, 100% {
    background-position: top, center;
  }
}

.lgl-loader {
  --lgl-bg-1: #ffffff;
  --lgl-bg-2: #f7f2ff;
  --lgl-bg-3: #eee6ff;

  --lgl-edge: rgba(111, 83, 214, 0.18);
  --lgl-edge-bright: rgba(255, 255, 255, 0.86);

  --lgl-shadow: rgba(54, 36, 116, 0.18);
  --lgl-shadow-strong: rgba(54, 36, 116, 0.3);
  --lgl-contact: rgba(49, 28, 104, 0.2);

  --lgl-text: #2d2059;

  --lgl-orb-1: #d8cbff;
  --lgl-orb-2: #a98cff;
  --lgl-orb-3: #7650f2;
  --lgl-orb-4: #3f18ad;
  --lgl-orb-deep: #251064;

  --lgl-glow: rgba(144, 112, 255, 0.42);
  --lgl-bubble: rgba(255, 255, 255, 0.94);
  --lgl-bubble-soft: rgba(255, 255, 255, 0.42);
  --lgl-focus: rgba(133, 107, 255, 0.34);

  display: inline-block;
  perspective: 72em;
  transform-style: preserve-3d;
}

.lgl-shell {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.95em;

  min-width: 12.2em;
  min-height: 4.7em;
  padding: 0.9em 1.2em;

  border-radius: 999em;
  border: 0.08em solid var(--lgl-edge);

  background: linear-gradient(
      180deg,
      rgba(255, 255, 255, 0.95) 0%,
      rgba(255, 255, 255, 0.5) 18%,
      transparent 42%
    ),
    radial-gradient(
      ellipse at 22% 8%,
      rgba(255, 255, 255, 0.92) 0%,
      rgba(255, 255, 255, 0.38) 24%,
      transparent 48%
    ),
    linear-gradient(
      165deg,
      var(--lgl-bg-1) 0%,
      var(--lgl-bg-2) 54%,
      var(--lgl-bg-3) 100%
    );

  box-shadow:
    0 1.45em 2.8em var(--lgl-shadow),
    0 0.65em 0.85em -0.65em var(--lgl-contact),
    inset 0 0.16em 0.22em var(--lgl-edge-bright),
    inset 0 -0.58em 1.05em rgba(91, 60, 188, 0.16),
    inset 0 -0.12em 0.16em rgba(54, 28, 132, 0.12),
    inset 0 0 0 0.055em rgba(255, 255, 255, 0.5);

  transform-style: preserve-3d;
  transform: rotateX(0deg) rotateY(0deg) translateZ(0);
  translate: 0 0;

  overflow: hidden;
  cursor: default;
  outline: none;
  user-select: none;

  transition:
    transform 260ms cubic-bezier(0.22, 1, 0.36, 1),
    box-shadow 260ms cubic-bezier(0.22, 1, 0.36, 1),
    border-color 260ms ease;

  animation: lgl-shell-float 4s ease-in-out infinite;
}

.lgl-shell::before {
  content: "";
  position: absolute;
  inset: 0.18em;
  border-radius: inherit;

  background: linear-gradient(
    115deg,
    transparent 0%,
    transparent 18%,
    rgba(255, 255, 255, 0.78) 28%,
    rgba(255, 255, 255, 0.22) 39%,
    transparent 58%
  );

  transform: translateX(-135%) skewX(-8deg);
  pointer-events: none;
  z-index: 3;

  animation: lgl-shell-sheen 4.2s cubic-bezier(0.22, 1, 0.36, 1) infinite;
}

.lgl-shell::after {
  content: "";
  position: absolute;
  width: 5em;
  height: 5em;
  right: -1.75em;
  bottom: -1.95em;

  border-radius: 50%;

  background: radial-gradient(
    circle,
    rgba(144, 112, 255, 0.42) 0%,
    rgba(144, 112, 255, 0.18) 34%,
    transparent 72%
  );

  filter: blur(0.28em);
  pointer-events: none;
  z-index: 0;
}

.lgl-loader:focus-visible .lgl-shell,
.lgl-shell:focus-visible {
  box-shadow:
    0 1.45em 2.8em var(--lgl-shadow),
    0 0 0 0.24em var(--lgl-focus),
    inset 0 0.16em 0.22em var(--lgl-edge-bright),
    inset 0 -0.58em 1.05em rgba(91, 60, 188, 0.16),
    inset 0 0 0 0.055em rgba(255, 255, 255, 0.5);
}

.lgl-loader:hover .lgl-shell {
  transform: rotateX(6deg) rotateY(-4deg) translateZ(0.3em);
  border-color: rgba(111, 83, 214, 0.24);

  box-shadow:
    0 1.75em 3.2em var(--lgl-shadow-strong),
    0 0.8em 1em -0.65em var(--lgl-contact),
    inset 0 0.18em 0.26em rgba(255, 255, 255, 0.92),
    inset 0 -0.68em 1.2em rgba(91, 60, 188, 0.19),
    inset 0 -0.12em 0.16em rgba(54, 28, 132, 0.14),
    inset 0 0 0 0.055em rgba(255, 255, 255, 0.58);
}

.lgl-loader:active .lgl-shell {
  transform: rotateX(2deg) rotateY(-1deg) translateZ(0) scale(0.985);
}

.lgl-orb {
  position: relative;
  width: 2.55em;
  height: 2.55em;
  flex: 0 0 auto;

  border-radius: 50%;
  overflow: hidden;
  isolation: isolate;

  background: linear-gradient(
      145deg,
      rgba(255, 255, 255, 0.52) 0%,
      rgba(255, 255, 255, 0.16) 24%,
      transparent 42%
    ),
    radial-gradient(
      ellipse at 42% 28%,
      var(--lgl-orb-1) 0%,
      var(--lgl-orb-2) 30%,
      var(--lgl-orb-3) 64%,
      var(--lgl-orb-4) 86%,
      var(--lgl-orb-deep) 100%
    );

  box-shadow:
    0 0.72em 1.2em rgba(72, 38, 184, 0.34),
    0 0 1.25em rgba(137, 104, 255, 0.28),
    inset 0 0.16em 0.22em rgba(255, 255, 255, 0.58),
    inset -0.22em -0.36em 0.56em rgba(31, 10, 100, 0.44),
    inset 0.16em 0.18em 0.28em rgba(255, 255, 255, 0.2),
    inset 0 0 0 0.075em rgba(255, 255, 255, 0.18);

  transform-style: preserve-3d;
  transform: translateZ(0.6em);

  animation:
    lgl-orb-float 2.8s cubic-bezier(0.37, 0, 0.22, 1) infinite,
    lgl-orb-wobble 4.8s ease-in-out infinite;
}

.lgl-orb::before {
  content: "";
  position: absolute;
  inset: 0.12em;
  border-radius: inherit;

  background: linear-gradient(
    155deg,
    rgba(255, 255, 255, 0.28) 0%,
    transparent 34%,
    rgba(46, 14, 137, 0.16) 74%,
    rgba(13, 4, 55, 0.28) 100%
  );

  mix-blend-mode: screen;
  pointer-events: none;
  z-index: 3;
}

.lgl-orb::after {
  content: "";
  position: absolute;
  left: -18%;
  top: 13%;
  width: 136%;
  height: 64%;

  border-radius: 48% 52% 54% 46% / 42% 44% 56% 58%;

  background: linear-gradient(
    180deg,
    rgba(255, 255, 255, 0.24) 0%,
    rgba(255, 255, 255, 0.08) 42%,
    transparent 72%
  );

  transform: rotate(-8deg);
  filter: blur(0.025em);
  pointer-events: none;
  z-index: 2;

  animation: lgl-liquid-surface 3.4s ease-in-out infinite;
}

.lgl-label {
