.cb-scene {
  --cb-cube-size: 120px;
  --cb-inner-multiplier: 0.5;
  --cb-color-inner: hsla(85, 100%, 50%, 0.85);
  --cb-color-outer: hsla(170, 70%, 50%, 0.2);
  --cb-blur: 2px;
  --cb-angle: -10deg;
  --cb-duration: 7s;

  position: relative;
  width: var(--cb-cube-size);
  height: var(--cb-cube-size);
  perspective: 750px;
}

.cb-cube-outer,
.cb-cube-inner {
  width: 100%;
  height: 100%;
  position: relative;
  transform-style: preserve-3d;
}

.cb-cube-inner {
  --cb-inner-scale: clamp(0.1, var(--cb-inner-multiplier), 0.6);
  scale: var(--cb-inner-scale);
  top: calc((1 - var(--cb-inner-scale)) * var(--cb-cube-size) / 2);
}

.cb-face {
  user-select: none;
  display: grid;
  place-items: center;
  position: absolute;
  width: var(--cb-cube-size);
  height: var(--cb-cube-size);
  box-shadow:
    inset 0 0 2px 0 #fff5,
    inset 0 0 12px -8px #fff1,
    inset 0 0 32px -10px #fff1,
    inset 0 0 64px -8px #fff1,
    inset 0 0 32px 16px #00000015;
  overflow: clip;

  font:
    500 1em "Inter",
    sans-serif;
  letter-spacing: -0.01em;
  color: #111;
  text-shadow:
    0 3px 4px #0008,
    0 -6px 6px #0005;
  animation: cb-blur-anim var(--cb-duration, 10s) linear infinite reverse;
}

.cb-face-front {
  transform: rotateY(0deg) translateZ(calc(var(--cb-cube-size) / 2));
  animation-delay: 0s;
}

.cb-face-right {
  transform: rotateY(90deg) translateZ(calc(var(--cb-cube-size) / 2));
  animation-delay: calc(var(--cb-duration, 10s) * -0.75);
}

.cb-face-back {
  transform: rotateY(180deg) translateZ(calc(var(--cb-cube-size) / 2));
  animation-delay: calc(var(--cb-duration, 10s) * -0.5);
}

.cb-face-left {
  transform: rotateY(-90deg) translateZ(calc(var(--cb-cube-size) / 2));
  animation-delay: calc(var(--cb-duration, 10s) * -0.25);
}

.cb-face-top {
  transform: rotateX(90deg) translateZ(calc(var(--cb-cube-size) / 2));
  animation: none;
}

.cb-face-bottom {
  transform: rotateX(-90deg) translateZ(calc(var(--cb-cube-size) / 2));
  filter: blur(20px);
  animation: none;
}

.cb-cube-inner .cb-face {
  animation: none;
  box-shadow:
    inset 0 0 1px 0px #000e,
    inset 0 0 12px -2px #0005,
    inset 0 0 32px 0px #0001,
    inset 0 0 64px 8px #0001;
}

@keyframes cb-blur-anim {
  0%,
  9% {
    filter: blur(0px);
  }

  10%,
  64% {
    filter: blur(10px);
  }

  65%,
  100% {
    filter: blur(0px);
  }
}

.cb-bg-color-in {
  background: var(--cb-color-inner);
}

.cb-bg-color-out {
  background-color: var(--cb-color-outer);
  background: linear-gradient(to bottom, #fff5, #0000),
    radial-gradient(
      circle at 50% -50%,
      var(--cb-color-inner) -20%,
      #fff0 30%,
      var(--cb-color-outer)
    );
}

.cb-cube-outer,
.cb-cube-inner {
  transform: rotateX(-20deg) rotateY(45deg);
}

.cb-cube-inner {
  position: absolute;
  transform-origin: center;
  scale: clamp(0.1, var(--cb-inner-multiplier), 0.6);
  animation: cb-rotate var(--cb-duration, 10s) linear infinite;
}

.cb-cube-outer {
  animation: cb-rotate var(--cb-duration, 10s) linear infinite reverse;
}

@keyframes cb-rotate {
  from {
    transform: rotateX(clamp(-40deg, var(--cb-angle), 40deg)) rotateY(45deg);
  }

  to {
    transform: rotateX(clamp(-40deg, var(--cb-angle), 40deg)) rotateY(405deg);
  }
}

.cb-blur {
  filter: blur(clamp(1px, var(--cb-blur, 7px), 20px));
}

.cb-cube-shadow {
  inset: 25%;
  transform-style: preserve-3d;
  position: absolute;
  background-color: #00000015;
  filter: blur(5px);
  animation: cb-rotate-shadow var(--cb-duration, 10s) linear infinite;
  z-index: 1;
  mix-blend-mode: multiply;
}

.cb-cube-shadow:nth-child(2) {
  inset: 0%;
  transform-style: preserve-3d;
  position: absolute;
  background-color: #00000015;
  filter: blur(5px);
  animation: cb-rotate-shadow var(--cb-duration, 10s) linear infinite reverse;
  z-index: 0;
}

@keyframes cb-rotate-shadow {
  from {
    transform: rotateX(calc(-100deg + clamp(-40deg, var(--cb-angle), 40deg)))
      rotateZ(45deg) translateZ(calc(var(--cb-cube-size) / 1.5));
  }

  to {
    transform: rotateX(calc(-100deg + clamp(-40deg, var(--cb-angle), 40deg)))
      rotateZ(405deg) translateZ(calc(var(--cb-cube-size) / 1.5));
  }
}

.cb-scene .cb-shadow {
  position: absolute;
  top: 45%;
  left: 35%;
  width: 50%;
  aspect-ratio: 1 / 1.5;
  background-color: #999;
  border-radius: 50%;
  transform: rotate(45deg);
  filter: blur(24px);
  mix-blend-mode: color-burn;
}

.cb-scene .cb-light {
  position: absolute;
  background-color: #555b;
  filter: blur(30px);
  mix-blend-mode: color-dodge;
  inset: 22%;
}

.cb-scene::before {
  content: "";
  position: absolute;
  inset: -100%;
  top: 50%;
  background-color: #0002;
  filter: blur(70px);
}

.ld-tetris {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

.ld-tetris__grid {
  position: relative;
  width: 80px;
  height: 160px;
  border: 2px solid #333;
  background: #fff;
  overflow: hidden;
}

.ld-tetris__piece {
  position: absolute;
  top: -40px;
  animation: ld-tetris-fall 3s linear infinite;
}

.ld-tetris__piece > i {
  display: block;
  position: absolute;
  width: 8px;
  height: 8px;
  background: #000;
  border: 1px solid #444;
  box-sizing: border-box;
}

/* I-piece (horizontal 4 cells) */
.ld-tetris__piece--i {
  width: 32px;
  left: 16px;
  animation-delay: 0s;
}
.ld-tetris__piece--i > i:nth-child(1) { left: 0; }
.ld-tetris__piece--i > i:nth-child(2) { left: 8px; }
.ld-tetris__piece--i > i:nth-child(3) { left: 16px; }
.ld-tetris__piece--i > i:nth-child(4) { left: 24px; }

/* O-piece (2x2) */
.ld-tetris__piece--o {
  width: 16px;
  left: 48px;
  animation-delay: 0.6s;
}
.ld-tetris__piece--o > i:nth-child(1) { left: 0; top: 0; }
.ld-tetris__piece--o > i:nth-child(2) { left: 8px; top: 0; }
.ld-tetris__piece--o > i:nth-child(3) { left: 0; top: 8px; }
.ld-tetris__piece--o > i:nth-child(4) { left: 8px; top: 8px; }

/* L-piece */
.ld-tetris__piece--l {
  width: 24px;
  left: 8px;
  animation-delay: 1.2s;
}
.ld-tetris__piece--l > i:nth-child(1) { left: 0; top: 0; }
.ld-tetris__piece--l > i:nth-child(2) { left: 0; top: 8px; }
.ld-tetris__piece--l > i:nth-child(3) { left: 0; top: 16px; }
.ld-tetris__piece--l > i:nth-child(4) { left: 8px; top: 16px; }

/* T-piece */
.ld-tetris__piece--t {
  width: 24px;
  left: 32px;
  animation-delay: 1.8s;
}
.ld-tetris__piece--t > i:nth-child(1) { left: 0; top: 0; }
.ld-tetris__piece--t > i:nth-child(2) { left: 8px; top: 0; }
.ld-tetris__piece--t > i:nth-child(3) { left: 16px; top: 0; }
.ld-tetris__piece--t > i:nth-child(4) { left: 8px; top: 8px; }

/* S-piece */
.ld-tetris__piece--s {
  width: 24px;
  left: 24px;
  animation-delay: 2.4s;
}
.ld-tetris__piece--s > i:nth-child(1) { left: 8px; top: 0; }
.ld-tetris__piece--s > i:nth-child(2) { left: 16px; top: 0; }
.ld-tetris__piece--s > i:nth-child(3) { left: 0; top: 8px; }
.ld-tetris__piece--s > i:nth-child(4) { left: 8px; top: 8px; }

@keyframes ld-tetris-fall {
  0% {
    top: -40px;
    opacity: 1;
  }
  85% {
    top: 120px;
    opacity: 1;
  }
  92% {
    top: 136px;
    opacity: 0.5;
    animation-timing-function: ease-out;
  }
  100% {
    top: 160px;
    opacity: 0;
  }
}

.ld-tetris__text {
  margin: 0;
  font-size: 12px;
  font-weight: 500;
  color: #333;
  font-family: monospace;
}

@media (prefers-color-scheme: dark) {
  .ld-tetris__grid {
    border-color: #ddd;
    background: #000;
  }
  .ld-tetris__piece > i {
    background: #fff;
    border-color: #aaa;
  }
  .ld-tetris__text {
    color: #ddd;
  }
}

.mn-menu {
  --glass-border: rgba(255, 255, 255, 0.4);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);

  width: calc(100% - 20px);
  max-width: 520px;
  backdrop-filter: blur(12px) saturate(180%) contrast(200%);
  -webkit-backdrop-filter: blur(12px) saturate(180%) contrast(200%);
  background: rgba(0, 122, 255, 0.404);
  border: 1px solid var(--glass-border);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.06);
  padding: 8px;
  border-radius: 99rem;
  display: flex;
  justify-content: center;
  gap: 8px;
  z-index: 50;
  isolation: isolate;
}

.mn-menu::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  box-shadow:
    inset 2px 2px 5px -2px rgba(255, 255, 255, 0.4),
    inset -2px -2px 5px 2px rgba(255, 255, 255, 0.4),
    inset 0 -2px 0 rgba(255, 255, 255, 0.2);
  pointer-events: none;
  z-index: -1;
}

.mn-menu a {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1 1 0;
  min-width: 0;
  color: rgba(255, 255, 255, 90%);
  text-decoration: none;
  padding: 10px 6px;
  border-radius: 999rem;
  -webkit-tap-highlight-color: transparent;
  transition:
    background 0.18s var(--ease-spring),
    color 0.18s var(--ease-spring),
    transform 0.18s var(--ease-spring),
    box-shadow 0.3s ease-in-out;
}

.mn-menu a.active {
  order: -1;
}

.mn-menu a:hover {
  transition:
    background 0.18s var(--ease-spring),
    color 0.18s var(--ease-spring),
    transform 0.18s var(--ease-spring),
    box-shadow 0.3s ease-in-out;
  background-color: rgba(255, 255, 255, 30%);
  box-shadow:
    inset 2px 2px 5px -2px rgba(255, 255, 255, 0.4),
    inset -2px -1px 5px 0 rgba(255, 255, 255, 0.4),
    inset 0 -2px 0 rgba(255, 255, 255, 0.2);
  transform: rotate(2.2);
  color: rgba(0, 122, 255, 70%);
}

.mn-menu a:hover ~ a.active,
.mn-menu a:focus ~ a.active {
  background: transparent;
  color: rgba(255, 255, 255, 90%);
}

.mn-menu a svg {
  width: 1.4rem;
  font-size: 1.4rem;
}

.mn-menu a span {
  font-size: 0.8rem;
  font-weight: 600;
  line-height: 1;
  margin-top: 4px;
}

.mn-menu a.active {
  background: rgb(237, 237, 237, 60%);
  color: rgba(0, 122, 255, 90%);
}

.mn-menu a:active {
  transform: scale(0.98);
}

