}

.custom-ui-switch input[type="checkbox"]:checked ~ .lights .light-on:after {
  box-shadow:
    0 0 10.4px 0 #4caf50,
    0 0 8.7px 1.3px #4caf50 inset,
    0 -1.3px 2.6px 2.6px #000 inset;
  background: radial-gradient(
