.switch {
  background-color: rgba(0, 0, 0, 0.2);
  border-radius: 30px;
  border: 4px solid rgba(58, 58, 58, 0.1);
  box-shadow: 0 0 6px rgba(0, 0, 0, 0.5) inset;
  height: 48px;
  margin: 2px;
  position: relative;
  width: 120px;
  display: inline-block;
  user-select: none;
}

.switch-check {
  position: absolute;
  visibility: hidden;
  user-select: none;
}

.switch-label {
  cursor: pointer;
  display: block;
  height: 42px;
  text-indent: -9999px;
  width: 115px;
  user-select: none;
}

.switch-label:before {
  background: #fff;
  background: -webkit-radial-gradient(45%, circle, rgb(255, 58, 58) 0%, rgb(255, 113, 113) 100%);
  border-radius: 10px;
  border: 1px solid #742323;
  box-shadow: 0 2px 5px rgba(255, 67, 48, 0.6), 0 0 5px rgba(255, 159, 109, 0.5) inset;
  content: "";
  display: block;
  height: 10px;
  left: -20%;
  position: absolute;
  top: 16px;
  transition: all 0.2s;
  width: 10px;
  z-index: 12;
  user-select: none;
}

.switch-label:after {
  background: #fff;
  background: -moz-radial-gradient(45%, circle, rgba(60, 60, 60, 0.6) 0%, rgba(151, 151, 151, 0.6) 100%);
  border-radius: 10px;
  border: 1px solid #111;
  box-shadow: 0 2px 5px rgba(20, 20, 20, 0.5);
  content: "";
  display: block;
  height: 10px;
  right: -20%;
  position: absolute;
  top: 16px;
  transition: all 0.2s;
  width: 10px;
  z-index: 12;
  user-select: none;
}

.switch-label span {
  background: linear-gradient(#4f4f4f, #2b2b2b);
  border-radius: 30px;
  border: 1px solid #1a1a1a;
  box-shadow: 0 0 4px rgba(0, 0, 0, 0.5), 0 1px 1px rgba(255, 255, 255, 0.1) inset, 0 -2px 0 rgba(0, 0, 0, 0.2) inset;
  display: block;
  height: 38px;
  left: 1px;
  position: absolute;
  top: 1px;
  -webkit-transition: all 0.2s linear;
  -moz-transition: all 0.2s linear;
  -o-transition: all 0.2s linear;
  transition: all 0.2s linear;
  width: 53px;
  user-select: none;
}

.switch-label span:before {
  background: #fff;
  background: -webkit-linear-gradient(left, rgba(48, 48, 48, 0.4), rgba(34, 34, 34, 0.4));
  background: linear-gradient(left, rgba(48, 48, 48, 0.4), rgba(34, 34, 34, 0.4));
  border-radius: 30px 10px 10px 30px;
  box-shadow: -2px 0 5px rgba(0, 0, 0, 0.2) inset;
  content: "";
  display: block;
  height: 33px;
  left: 2px;
  position: absolute;
  top: 2px;
  width: 21px;
  user-select: none;
}

.switch-label span:after {
  background: #fff;
  background: -webkit-linear-gradient(right, rgba(48, 48, 48, 0.4), rgba(34, 34, 34, 0.4));
  border-radius: 10px 30px 30px 10px;
  box-shadow: 2px 0 5px rgba(0, 0, 0, 0.2) inset;
  content: "";
  display: block;
  height: 33px;
  position: absolute;
  right: 2px;
  top: 2px;
  width: 21px;
  user-select: none;
}

.switch-check:checked + .switch-label span {
  left: 59px;
}

.switch-check:checked + .switch-label:before {
  background: -webkit-radial-gradient(45%, circle, rgba(60, 60, 60, 0.6) 0%, rgba(151, 151, 151, 0.6) 100%);
  border: 1px solid #111;
  box-shadow: 0 2px 5px rgba(20, 20, 20, 0.5);
  user-select: none;
}

.switch-check:checked + .switch-label:after {
  background: -webkit-radial-gradient(45%, circle, lightgreen  0%, lightgreen 100%);
  border: 1px solid #004562;
  box-shadow: 0 2px 5px green, 0 0 5px green inset;
  user-select: none;
}

.conic-label {
  position: relative;
  display: inline-flex;
  align-items: center;
  cursor: pointer;
}

.conic-input {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border-width: 0;
}

.conic-track {
  position: relative;
  box-shadow: 1px 3px 0px 0px #000;
  background: linear-gradient(to right, #fb7185, #7f1d1d);
  border-radius: 9999px;
  outline: none;
  transition-duration: 1000ms;
  width: 6rem;
  height: 3rem;
  box-shadow: 1px 3px 0px 0px #000, 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
}

.conic-track:after {
  content: '';
  border-radius: 9999px;
  position: absolute;
  background: conic-gradient(from 135deg, #b2a9a9, #b2a8a8, #ffffff, #d7dbd9, #ffffff, #b2a8a8);
  outline: none;
  height: 2.5rem;
  width: 2.5rem;
  top: 0.25rem;
  left: 0.25rem;
  transition: transform 300ms;
}

.conic-input:focus-visible + .conic-track {
  outline: none;
}

.conic-input:checked + .conic-track {
  background: linear-gradient(to right, #10b981, #064e3b);
}

.conic-input:checked + .conic-track:after {
  transform: translateX(3rem) rotate(180deg);
}

.conic-label:hover .conic-track:after {
  transform: scale(0.95);
}

.conic-label:hover .conic-input:checked + .conic-track:after {
  transform: translateX(3rem) rotate(180deg) scale(0.95);
}

